import Layout from "@/components/layout";
import { Link } from "wouter";
import {
  Shield, ArrowRight, CheckCircle, ChevronDown, Lock, Calendar, Search,
} from "lucide-react";
import { useState } from "react";

// ── Price constants ───────────────────────────────────────────────────────────
const PRICE_SETUP_FROM = "desde 97€";
const PRICE_SETUP_FULL = "147€";
const PRICE_MONTHLY = "19€/mes";
const PRICE_MONTHLY_FULL = "29€/mes";

const CALENDLY_URL = import.meta.env.VITE_CALENDLY_URL ?? "#";

// ── FAQ accordion item ────────────────────────────────────────────────────────
interface FaqItem {
  q: string;
  a: string;
}

function FaqRow({ item }: { item: FaqItem }) {
  const [open, setOpen] = useState(false);
  return (
    <div className="border-b border-slate-700/60 last:border-0">
      <button
        onClick={() => setOpen(!open)}
        className="w-full flex items-center justify-between gap-3 py-4 text-left text-sm font-semibold text-white hover:text-[#FFD400] transition-colors"
      >
        <span>{item.q}</span>
        <ChevronDown
          className={`w-4 h-4 shrink-0 text-slate-400 transition-transform duration-200 ${open ? "rotate-180" : ""}`}
        />
      </button>
      {open && (
        <p className="pb-4 text-sm text-slate-400 leading-relaxed">{item.a}</p>
      )}
    </div>
  );
}

// ── Main component ────────────────────────────────────────────────────────────
export default function Home() {
  const painPoints = [
    "Usas el mismo email para clientes, Hacienda y redes sociales",
    "Tu móvil personal es también tu herramienta de trabajo",
    "No sabes si tu email ha sido filtrado en alguna brecha",
    "Tienes contraseñas repetidas o anotadas en algún sitio",
    "No tienes 2FA activado en tu gestor de facturación",
    'Crees que "a mí no me va a pasar"',
  ];

  const auditItems = [
    "Análisis de brechas de email (Have I Been Pwned + dark web básico)",
    "Estado del 2FA en todas tus cuentas clave",
    "Seguridad de tus contraseñas (sin verlas)",
    "Configuración de privacidad de tu móvil",
    "Huella digital básica: qué datos tuyos están públicos",
    "Seguridad del email profesional (SPF, DKIM)",
    "Revisión de dispositivos y actualizaciones",
    "Permisos de apps instaladas",
    "Configuración de backups",
    "Plan de acción priorizado con los 3 cambios más urgentes",
  ];

  const basicFeatures = [
    "Auditoría gratis de 20-30 min incluida",
    "Configuración de 2FA en cuentas clave",
    "Gestor de contraseñas instalado y configurado",
    "Revisión de privacidad móvil y dispositivos",
    "Informe de brechas personalizado",
    "Entrega del plan de acción en 48h",
  ];

  const monthlyFeatures = [
    "Alertas inmediatas si tus datos aparecen en una brecha",
    "Revisión mensual de tu estado de seguridad",
    "Soporte prioritario por email",
    "Actualizaciones del protocolo de seguridad",
    "Acceso directo a Flo para consultas urgentes",
  ];

  const steps = [
    {
      icon: <Calendar className="w-6 h-6 text-[#FFD400]" />,
      title: "Reserva tu auditoría gratis",
      desc: "Eliges hueco en mi calendario. Sin coste, sin compromiso. 20-30 min por Zoom o Loom.",
    },
    {
      icon: <Search className="w-6 h-6 text-[#FFD400]" />,
      title: "Analizamos tus vulnerabilidades reales",
      desc: "Revisamos juntos tus cuentas, dispositivos y configuraciones. Ves exactamente qué está expuesto y qué riesgo supone.",
    },
    {
      icon: <Shield className="w-6 h-6 text-[#FFD400]" />,
      title: "Lo blindamos",
      desc: "Si decides continuar, aplico el Setup Blindaje Básico: configuro, corrijo y te entrego un informe. Listo en 48h.",
    },
  ];

  const faqs: FaqItem[] = [
    {
      q: "¿Necesito saber de tecnología?",
      a: "No. Te explico todo en lenguaje claro. Mi trabajo es que entiendas qué tienes y qué riesgo supone, no marearte con tecnicismos.",
    },
    {
      q: "¿Cuánto tiempo me lleva?",
      a: "La auditoría son 20-30 min. El setup lo hago yo y te entrego el informe en 48h. Tu tiempo invertido: menos de 1 hora total.",
    },
    {
      q: "¿Funciona aunque tenga iPhone/Android/Mac/Windows?",
      a: "Sí. Trabajo con todos los sistemas y dispositivos habituales.",
    },
    {
      q: "¿Y si ya tengo antivirus?",
      a: "El antivirus solo cubre una parte mínima. Las brechas más comunes son contraseñas reutilizadas, 2FA desactivado y configuraciones por defecto. Eso no lo detecta ningún antivirus.",
    },
    {
      q: "¿Necesito el plan mensual?",
      a: "No es obligatorio. Muchos clientes empiezan con el setup único y añaden la guardia mensual cuando ven el valor. Sin presión.",
    },
  ];

  return (
    <Layout>

      {/* ── 1. HERO ── */}
      <header className="flex flex-col items-center text-center space-y-5 mb-10">
        <div className="inline-flex items-center gap-2 px-3 py-1.5 bg-[#FFD400]/10 border border-[#FFD400]/30 rounded-full text-[#FFD400] text-xs font-bold uppercase tracking-wide">
          <Shield className="w-3.5 h-3.5" />
          Especialista en privacidad digital para autónomos
        </div>

        <h1 className="text-3xl font-black text-white leading-tight tracking-tight">
          Tu negocio español tiene brechas de seguridad.{" "}
          <span className="text-[#FFD400]">Yo las cierro mientras tú trabajas.</span>
        </h1>

        <p className="text-slate-300 text-sm leading-relaxed max-w-sm mx-auto">
          INCIBE gestionó <strong className="text-white">122.223 incidentes en 2025</strong> (+26%). El 87% de autónomos tiene vulnerabilidades graves que pueden costarles miles de euros. Yo las encuentro y las soluciono contigo en 20 minutos.
        </p>

        <a
          href={CALENDLY_URL}
          target={CALENDLY_URL !== "#" ? "_blank" : undefined}
          rel="noopener noreferrer"
          className="w-full group bg-[#FFD400] hover:bg-[#FFE033] text-[#0F2438] font-black py-4 px-6 rounded-xl shadow-lg hover:shadow-[#FFD400]/30 transition-all duration-300 transform hover:-translate-y-0.5 flex items-center justify-center gap-2 text-base"
        >
          Reservar Auditoría Gratis →
          <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
        </a>

        <Link href="/quiz">
          <a className="w-full glass-card border border-slate-700/60 hover:border-[#FFD400]/40 rounded-xl py-3 px-4 text-sm text-slate-200 font-semibold flex items-center justify-center gap-2 transition-colors">
            Ver mi Privacy Score gratis
          </a>
        </Link>

        <p className="text-slate-500 text-xs">Sin compromiso · 20-30 min · Por Zoom o Loom</p>
      </header>

      {/* ── 2. PAIN STATS ── */}
      <section className="w-full mb-10 space-y-4">
        <div className="grid grid-cols-3 gap-3">
          {[
            { stat: "122.223", label: "incidentes gestionados por INCIBE en 2025" },
            { stat: "+26%", label: "de aumento respecto al año anterior" },
            { stat: "45.445", label: "fraudes online a autónomos y pymes" },
          ].map(({ stat, label }) => (
            <div
              key={stat}
              className="glass-card rounded-xl p-3 border border-slate-700/50 text-center flex flex-col gap-1"
            >
              <span className="text-xl font-black text-[#FFD400]">{stat}</span>
              <span className="text-[10px] text-slate-400 leading-tight">{label}</span>
            </div>
          ))}
        </div>
        <p className="text-center text-[10px] text-slate-600">Fuente: INCIBE Informe Anual 2025</p>
      </section>

      {/* ── 3. PAIN SECTION ── */}
      <section className="w-full mb-10 space-y-4">
        <div className="text-center space-y-1">
          <h2 className="text-lg font-black text-white">Si eres autónomo español, probablemente estás expuesto</h2>
          <p className="text-xs text-slate-400">¿Te suena alguno de estos?</p>
        </div>
        <div className="space-y-2">
          {painPoints.map((point) => (
            <div
              key={point}
              className="flex items-start gap-3 p-3 rounded-xl glass-card border border-slate-700/40"
            >
              <span className="text-base shrink-0">❌</span>
              <p className="text-sm text-slate-300 leading-snug">{point}</p>
            </div>
          ))}
        </div>
      </section>

      {/* ── 4. HOW IT WORKS ── */}
      <section className="w-full mb-10 space-y-4">
        <div className="text-center space-y-1">
          <h2 className="text-lg font-black text-white">Cómo funciona. Simple y directo.</h2>
        </div>
        <div className="space-y-4">
          {steps.map((step, i) => (
            <div key={i} className="flex items-start gap-4 p-4 glass-card rounded-xl border border-slate-700/50">
              <div className="w-10 h-10 rounded-full bg-[#FFD400]/10 border border-[#FFD400]/20 flex items-center justify-center shrink-0">
                {step.icon}
              </div>
              <div className="space-y-1">
                <p className="font-bold text-sm text-white">
                  <span className="text-[#FFD400] mr-1">{i + 1}.</span>
                  {step.title}
                </p>
                <p className="text-xs text-slate-400 leading-relaxed">{step.desc}</p>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* ── 5. AUDIT INCLUDES ── */}
      <section className="w-full mb-10 space-y-4">
        <div className="text-center">
          <h2 className="text-lg font-black text-white">¿Qué revisamos en la auditoría?</h2>
        </div>
        <div className="glass-card rounded-xl border border-slate-700/50 p-5 space-y-3">
          {auditItems.map((item) => (
            <div key={item} className="flex items-start gap-2.5">
              <CheckCircle className="w-4 h-4 text-[#FFD400] shrink-0 mt-0.5" />
              <p className="text-sm text-slate-300 leading-snug">{item}</p>
            </div>
          ))}
        </div>
      </section>

      {/* ── 6. PRICING ── */}
      <section className="w-full mb-10 space-y-4">
        <div className="text-center">
          <h2 className="text-lg font-black text-white">Precios claros. Sin letra pequeña.</h2>
        </div>

        {/* Featured card */}
        <div className="rounded-xl border-2 border-[#FFD400] bg-[#FFD400]/5 p-5 space-y-4">
          <div className="flex items-start justify-between">
            <div>
              <span className="text-[10px] font-black text-[#0F2438] bg-[#FFD400] px-2 py-0.5 rounded uppercase">Más popular</span>
              <h3 className="mt-2 text-base font-black text-white">Blindaje Básico</h3>
              <p className="text-xs text-slate-400 mt-0.5">Auditoría gratis de 20-30 min incluida</p>
            </div>
            <div className="text-right shrink-0">
              <p className="text-2xl font-black text-[#FFD400]">{PRICE_SETUP_FROM}</p>
              <p className="text-[10px] text-slate-500 uppercase font-bold">pago único</p>
            </div>
          </div>
          <div className="space-y-2">
            {basicFeatures.map((f) => (
              <div key={f} className="flex items-start gap-2">
                <CheckCircle className="w-3.5 h-3.5 text-[#FFD400] shrink-0 mt-0.5" />
                <p className="text-xs text-slate-300">{f}</p>
              </div>
            ))}
          </div>
          <a
            href={CALENDLY_URL}
            target={CALENDLY_URL !== "#" ? "_blank" : undefined}
            rel="noopener noreferrer"
            className="block w-full text-center bg-[#FFD400] hover:bg-[#FFE033] text-[#0F2438] font-black py-3 rounded-lg text-sm transition-colors"
          >
            Empezar con Auditoría Gratis
          </a>
        </div>

        {/* Monthly card */}
        <div className="rounded-xl border border-slate-700/50 glass-card p-5 space-y-4">
          <div className="flex items-start justify-between">
            <div>
              <h3 className="text-base font-black text-white">Guardia Digital</h3>
              <p className="text-xs text-slate-400 mt-0.5">Protección continua</p>
            </div>
            <div className="text-right shrink-0">
              <p className="text-2xl font-black text-[#FFD400]">{PRICE_MONTHLY}</p>
              <p className="text-[10px] text-slate-500 uppercase font-bold">mensual</p>
            </div>
          </div>
          <div className="space-y-2">
            {monthlyFeatures.map((f) => (
              <div key={f} className="flex items-start gap-2">
                <CheckCircle className="w-3.5 h-3.5 text-[#FFD400] shrink-0 mt-0.5" />
                <p className="text-xs text-slate-300">{f}</p>
              </div>
            ))}
          </div>
          <a
            href={CALENDLY_URL}
            target={CALENDLY_URL !== "#" ? "_blank" : undefined}
            rel="noopener noreferrer"
            className="block w-full text-center border border-slate-600 hover:border-[#FFD400]/60 text-slate-200 font-bold py-3 rounded-lg text-sm transition-colors"
          >
            Añadir protección mensual
          </a>
        </div>

        <p className="text-xs text-slate-500 text-center leading-relaxed px-2">
          ¿Hacerlo tú solo? Entre cursos, tiempo invertido y errores cometidos, el coste real supera los 500€ y semanas de tu vida.
        </p>
      </section>

      {/* ── 7. GUARANTEE ── */}
      <section className="w-full mb-10">
        <div className="glass-card rounded-xl border border-slate-700/50 p-5 text-center space-y-3">
          <p className="text-2xl">🛡️</p>
          <h2 className="text-base font-black text-white">Garantía de 14 días</h2>
          <p className="text-sm text-slate-400 leading-relaxed">
            Si en 14 días desde el Setup no ves una diferencia clara y medible en tu seguridad digital, te devuelvo el 100% del dinero. Sin preguntas.
          </p>
          <div className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-slate-800 border border-slate-700 rounded-full text-xs font-semibold text-slate-300">
            <Lock className="w-3.5 h-3.5 text-[#FFD400]" />
            Pago seguro · Garantía total · Sin permanencia
          </div>
        </div>
      </section>

      {/* ── 8. FAQ ── */}
      <section className="w-full mb-10 space-y-3">
        <div className="text-center">
          <h2 className="text-lg font-black text-white">Preguntas frecuentes</h2>
        </div>
        <div className="glass-card rounded-xl border border-slate-700/50 px-5 py-2">
          {faqs.map((item) => (
            <FaqRow key={item.q} item={item} />
          ))}
        </div>
      </section>

      {/* ── 9. FINAL CTA ── */}
      <section className="w-full mb-4 space-y-4 text-center">
        <h2 className="text-xl font-black text-white leading-tight">
          Tu negocio no puede esperar a ser el próximo incidente
        </h2>
        <p className="text-sm text-slate-400">La auditoría es gratis. El riesgo de no hacerla, no lo es.</p>
        <a
          href={CALENDLY_URL}
          target={CALENDLY_URL !== "#" ? "_blank" : undefined}
          rel="noopener noreferrer"
          className="w-full group bg-[#FFD400] hover:bg-[#FFE033] text-[#0F2438] font-black py-4 px-6 rounded-xl shadow-lg hover:shadow-[#FFD400]/30 transition-all duration-300 transform hover:-translate-y-0.5 flex items-center justify-center gap-2 text-base"
        >
          Reservar Auditoría Gratis Ahora →
          <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
        </a>
        <p className="text-slate-500 text-xs">Sin coste · Sin compromiso · 20-30 minutos</p>
      </section>

    </Layout>
  );
}

